import { useEffect, useState } from "react";
import { PageShell } from "@/components/orderly/PageShell";
import { Wallet, ExternalLink, Lightbulb, Globe } from "lucide-react";
import { useTranslation } from "@/i18n";
import { storageKey } from "@/utils/storage";

export default function ReownConfigPage() {
  const { t } = useTranslation();
  const [walletConnectProjectId, setWalletConnectProjectId] = useState("");
  const [toast, setToast] = useState<string | null>(null);

  useEffect(() => {
    setWalletConnectProjectId(
      localStorage.getItem(storageKey("orderlyWalletConnectProjectId")) || ""
    );
  }, []);

  useEffect(() => {
    localStorage.setItem(
      storageKey("orderlyWalletConnectProjectId"),
      walletConnectProjectId
    );
  }, [walletConnectProjectId]);

  function showToast(message: string) {
    setToast(message);
    setTimeout(() => setToast(null), 3000);
  }

  return (
    <PageShell pageTitle="Reown Configuration">
      <div className="rounded-xl border border-(--line-subtle) bg-(--bg-surface-primary) p-6">
        <div className="mb-5 flex items-center gap-2">
          <div className="flex h-8 w-8 items-center justify-center rounded-md bg-[rgba(188,135,255,0.12)] text-(--fg-brand)">
            <Wallet className="h-4 w-4" />
          </div>
        </div>

        <div className="mb-5 rounded-lg border border-(--line-subtle) bg-(--bg-surface-secondary) p-4">
          <div className="flex items-start gap-3">
            <Wallet className="mt-0.5 h-5 w-5 shrink-0 text-(--fg-brand)" />
            <div>
              <p className="mb-2 text-sm font-medium text-(--fg-brand)">
                Enhanced wallet connectivity
              </p>
              <p className="mb-3 text-sm text-(--fg-secondary)">
                <span className="font-medium text-(--fg-brand)">
                  Reown (formerly WalletConnect)
                </span>{" "}
                provides universal wallet connectivity, enabling users to
                connect with any wallet on any device.
              </p>

              <div className="space-y-3">
                <div>
                  <h4 className="mb-1 text-base font-bold text-(--fg-primary)">
                    Key benefits:
                  </h4>
                  <ul className="list-disc space-y-1 pl-4 text-sm text-(--fg-secondary)">
                    <li>
                      <strong>Mobile wallet support</strong> — seamless QR
                      scanning and deep-linking
                    </li>
                    <li>
                      <strong>Cross-platform access</strong> — desktop, mobile,
                      and web
                    </li>
                    <li>
                      <strong>Universal compatibility</strong> — works with 300+
                      wallets
                    </li>
                    <li>
                      <strong>Better UX</strong> — one-tap connection flows
                    </li>
                    <li>
                      <strong>Secure connections</strong> — end-to-end encrypted
                      sessions
                    </li>
                  </ul>
                </div>

                <div className="rounded-lg border border-[rgba(217,171,82,0.25)] bg-[rgba(217,171,82,0.08)] p-3">
                  <h4 className="mb-1 text-base font-bold text-[#D9AB52]">
                    Why this matters
                  </h4>
                  <p className="text-sm text-(--fg-secondary)">
                    Without Reown, users on mobile or with non-browser-extension
                    wallets may struggle to connect. Adding a project ID
                    dramatically improves conversion and retention.
                  </p>
                </div>
              </div>
            </div>
          </div>
        </div>

        <div className="mb-4">
          <label
            htmlFor="walletConnectProjectId"
            className="mb-1.5 block text-sm text-(--fg-secondary)"
          >
            Reown Project ID
          </label>
          <input
            id="walletConnectProjectId"
            type="text"
            value={walletConnectProjectId}
            onChange={e => setWalletConnectProjectId(e.target.value)}
            placeholder="e.g. a1b2c3d4e5f6..."
            className="w-full rounded-lg border border-(--line-subtle) bg-(--bg-input) px-3 py-2 text-sm text-(--fg-primary) outline-none transition-colors focus:border-(--line-brand)"
          />
        </div>

        <div className="mb-5 space-y-3 text-sm text-(--fg-secondary)">
          <div>
            <strong className="text-(--fg-brand)">
              How to get a Project ID
            </strong>
            <ol className="mt-1 list-decimal space-y-1 pl-4">
              <li>
                Create a free account at{" "}
                <a
                  href="https://dashboard.reown.com"
                  target="_blank"
                  rel="noopener noreferrer"
                  className="inline-flex items-center gap-1 font-medium text-(--fg-brand) hover:underline"
                >
                  dashboard.reown.com
                  <ExternalLink className="h-3 w-3" />
                </a>
              </li>
              <li>Click “Create” and follow the setup wizard</li>
              <li>Copy your Project ID and paste it above</li>
            </ol>
          </div>

          <div className="rounded-lg border border-(--line-brand)/20 bg-[rgba(188,135,255,0.06)] p-3">
            <h4 className="mb-1 flex items-center gap-2 text-base font-bold text-(--fg-brand)">
              <Lightbulb className="h-4 w-4" />
              Integration Notes
            </h4>
            <ul className="space-y-1 text-sm text-(--fg-secondary)">
              <li>Your Project ID is safe to expose in client-side code</li>
              <li>It identifies your app to the Reown network</li>
              <li>Required for WalletConnect v2 to function</li>
              <li>Free tier includes generous usage limits</li>
            </ul>
          </div>

          <div className="rounded-lg border border-[rgba(217,171,82,0.25)] bg-[rgba(217,171,82,0.08)] p-3">
            <h4 className="mb-1 flex items-center gap-2 text-base font-bold text-[#D9AB52]">
              <Globe className="h-4 w-4" />
              Domain allowlist required
            </h4>
            <p className="mb-2 text-sm text-(--fg-secondary)">
              You must add your production domain to the Reown dashboard so
              wallet sessions are authorized.
            </p>
            <div className="space-y-2">
              <p className="text-sm text-(--fg-secondary)">
                <strong>How to configure domains:</strong>
              </p>
              <ol className="list-decimal space-y-1 pl-4 text-sm text-(--fg-secondary)">
                <li>Open your project in the Reown dashboard</li>
                <li>
                  Navigate to{" "}
                  <code className="rounded bg-(--bg-input) px-1">
                    Settings &gt; Domains
                  </code>
                </li>
                <li>
                  Click{" "}
                  <code className="rounded bg-(--bg-input) px-1">
                    Add Domain
                  </code>
                </li>
                <li>
                  Enter your production domain (e.g.{" "}
                  <code className="rounded bg-(--bg-input) px-1">
                    https://your-domain.com
                  </code>
                  )
                </li>
              </ol>
              <div className="mt-2 rounded border border-(--line-subtle) bg-(--bg-input) p-2">
                <p className="text-xs text-(--fg-secondary)">
                  <strong>Pro tip:</strong> Add both{" "}
                  <code className="rounded bg-(--bg-hover) px-1">
                    https://your-domain.com
                  </code>{" "}
                  and{" "}
                  <code className="rounded bg-(--bg-hover) px-1">
                    https://www.your-domain.com
                  </code>{" "}
                  to avoid connection issues.
                </p>
              </div>
            </div>
          </div>
        </div>

        <div className="flex items-center gap-3">
          <button
            type="button"
            onClick={() => showToast(t("reownConfig.saved"))}
            className="inline-flex items-center gap-2 rounded-full px-5 py-2.5 text-sm font-medium text-(--fg-primary) transition-opacity hover:opacity-90"
            style={{ background: "var(--bg-brand-grad)" }}
          >
            Save configuration
          </button>
        </div>
      </div>

      {toast && (
        <div className="fixed bottom-5 left-1/2 z-100 -translate-x-1/2 rounded-full border border-(--line-brand) bg-(--bg-surface-primary) px-5 py-2.5 text-sm font-medium text-(--fg-primary) shadow-xl">
          {toast}
        </div>
      )}
    </PageShell>
  );
}
